<?php
namespace Tests\Unit\Domain\Combat;use App\Domain\Characters\CharacterStatsCalculator;use App\Domain\Combat\Factories\CharacterCombatantFactory;use App\Domain\Combat\Factories\MonsterCombatantFactory;use App\Domain\Stats\DamageReductionCalculator;use App\Models\Character;use App\Models\Monster;use PHPUnit\Framework\TestCase;class CombatantFactoryTest extends TestCase{public function test_character_and_monster_use_shared_stats(){$r=new DamageReductionCalculator();$c=new Character();$c->setRawAttributes(['id'=>4,'name'=>'Hero','base_max_health'=>100,'current_health'=>90,'base_attack'=>10,'base_defense'=>5,'base_accuracy'=>80,'base_evasion'=>5,'base_critical_rate'=>'5.00']);$cs=(new CharacterStatsCalculator($r))->calculate($c);$snapshot=(new CharacterCombatantFactory())->make($c,$cs);$this->assertSame(round($r->calculate(5),2),$snapshot->damageReductionRate());$m=new Monster();$m->setRawAttributes(['id'=>2,'name'=>'Wolf','max_health'=>30,'attack'=>6,'defense'=>5,'accuracy_rate'=>'75.00','evasion_rate'=>'8.00','critical_chance'=>'3.00']);$ms=(new MonsterCombatantFactory($r))->make($m);$this->assertSame($r->calculate(5),$ms->damageReductionRate());$this->assertSame(30,$ms->currentHealth());}}
